package ru.memearena.tournament.domain; import jakarta.persistence.*; import java.time.*; import java.util.*; @Entity @Table(name="tournament_entry") public class TournamentEntry{ @Id public UUID id; @Column(name="tournament_id") public UUID tournamentId; @Column(name="meme_id") public UUID memeId; public int seed; @Column(name="eliminated_round") public Integer eliminatedRound; @Column(name="final_position") public Integer finalPosition; @Column(name="created_at") public Instant createdAt; protected TournamentEntry(){} public TournamentEntry(UUID id,UUID t,UUID m,int s,Instant now){this.id=id;this.tournamentId=t;this.memeId=m;this.seed=s;this.createdAt=now;} public UUID getMemeId(){return memeId;} public int getSeed(){return seed;} }
